package types

// MessageServiceType identifies the specific kind of service (system) message,
// such as a new chat title, pinned message, or phone call event. Service
// messages are generated by Telegram itself rather than sent by users.
type MessageServiceType string

const (
	// MessageServiceTypeUnsupported represents a service action not recognized by this library.
	MessageServiceTypeUnsupported MessageServiceType = "unsupported"
	// MessageServiceTypeCustomAction is a custom action text shown in the chat.
	MessageServiceTypeCustomAction MessageServiceType = "custom_action"
	// MessageServiceTypeNewChatMembers is sent when new members join the chat.
	MessageServiceTypeNewChatMembers MessageServiceType = "new_chat_members"
	// MessageServiceTypeLeftChatMember is sent when a member leaves the chat.
	MessageServiceTypeLeftChatMember MessageServiceType = "left_chat_member"
	// MessageServiceTypeChatOwnerLeft is sent when the chat owner leaves the group.
	MessageServiceTypeChatOwnerLeft MessageServiceType = "chat_owner_left"
	// MessageServiceTypeChatOwnerChanged is sent when chat ownership is transferred.
	MessageServiceTypeChatOwnerChanged MessageServiceType = "chat_owner_changed"
	// MessageServiceTypeNewChatTitle is sent when the chat title is changed.
	MessageServiceTypeNewChatTitle MessageServiceType = "new_chat_title"
	// MessageServiceTypeNewChatPhoto is sent when the chat photo is changed.
	MessageServiceTypeNewChatPhoto MessageServiceType = "new_chat_photo"
	// MessageServiceTypeDeleteChatPhoto is sent when the chat photo is removed.
	MessageServiceTypeDeleteChatPhoto MessageServiceType = "delete_chat_photo"
	// MessageServiceTypeForumTopicCreated is sent when a new forum topic is created.
	MessageServiceTypeForumTopicCreated MessageServiceType = "forum_topic_created"
	// MessageServiceTypeForumTopicClosed is sent when a forum topic is closed.
	MessageServiceTypeForumTopicClosed MessageServiceType = "forum_topic_closed"
	// MessageServiceTypeForumTopicReopened is sent when a forum topic is reopened.
	MessageServiceTypeForumTopicReopened MessageServiceType = "forum_topic_reopened"
	// MessageServiceTypeForumTopicEdited is sent when a forum topic's title or icon is changed.
	MessageServiceTypeForumTopicEdited MessageServiceType = "forum_topic_edited"
	// MessageServiceTypeGeneralForumTopicHidden is sent when the General topic is hidden.
	MessageServiceTypeGeneralForumTopicHidden MessageServiceType = "general_forum_topic_hidden"
	// MessageServiceTypeGeneralForumTopicUnhidden is sent when the General topic is unhidden.
	MessageServiceTypeGeneralForumTopicUnhidden MessageServiceType = "general_forum_topic_unhidden"
	// MessageServiceTypeGroupChatCreated is sent when a basic group is created.
	MessageServiceTypeGroupChatCreated MessageServiceType = "group_chat_created"
	// MessageServiceTypeChannelChatCreated is sent when a channel is created.
	MessageServiceTypeChannelChatCreated MessageServiceType = "channel_chat_created"
	// MessageServiceTypeSupergroupChatCreated is sent when a supergroup is created.
	MessageServiceTypeSupergroupChatCreated MessageServiceType = "supergroup_chat_created"
	// MessageServiceTypeMigrateToChatID is sent when a group migrates to a supergroup.
	MessageServiceTypeMigrateToChatID MessageServiceType = "migrate_to_chat_id"
	// MessageServiceTypeMigrateFromChatID is sent in the destination supergroup after migration.
	MessageServiceTypeMigrateFromChatID MessageServiceType = "migrate_from_chat_id"
	// MessageServiceTypePinnedMessage is sent when a message is pinned in the chat.
	MessageServiceTypePinnedMessage MessageServiceType = "pinned_message"
	// MessageServiceTypeGameHighScore is sent when a game high score is updated.
	MessageServiceTypeGameHighScore MessageServiceType = "game_high_score"
	// MessageServiceTypeGiveawayCreated is sent when a giveaway is created.
	MessageServiceTypeGiveawayCreated MessageServiceType = "giveaway_created"
	// MessageServiceTypeGiveawayCompleted is sent when a giveaway ends and winners are selected.
	MessageServiceTypeGiveawayCompleted MessageServiceType = "giveaway_completed"
	// MessageServiceTypeManagedBotCreated is sent when a managed bot is added to the chat.
	MessageServiceTypeManagedBotCreated MessageServiceType = "managed_bot_created"
	// MessageServiceTypePollOptionAdded is sent when an option is added to a poll.
	MessageServiceTypePollOptionAdded MessageServiceType = "poll_option_added"
	// MessageServiceTypePollOptionDeleted is sent when an option is removed from a poll.
	MessageServiceTypePollOptionDeleted MessageServiceType = "poll_option_deleted"
	// MessageServiceTypePremiumGiftCode is sent when a premium gift code is shared.
	MessageServiceTypePremiumGiftCode MessageServiceType = "premium_gift_code"
	// MessageServiceTypeGiftedPremium is sent when Telegram Premium is gifted.
	MessageServiceTypeGiftedPremium MessageServiceType = "gifted_premium"
	// MessageServiceTypeGiftedStars is sent when Telegram Stars are gifted.
	MessageServiceTypeGiftedStars MessageServiceType = "gifted_stars"
	// MessageServiceTypeGiftedTon is sent when TON cryptocurrency is gifted.
	MessageServiceTypeGiftedTon MessageServiceType = "gifted_ton"
	// MessageServiceTypeVideoChatStarted is sent when a video chat (group call) starts.
	MessageServiceTypeVideoChatStarted MessageServiceType = "video_chat_started"
	// MessageServiceTypeVideoChatEnded is sent when a video chat (group call) ends.
	MessageServiceTypeVideoChatEnded MessageServiceType = "video_chat_ended"
	// MessageServiceTypeVideoChatScheduled is sent when a video chat is scheduled.
	MessageServiceTypeVideoChatScheduled MessageServiceType = "video_chat_scheduled"
	// MessageServiceTypeVideoChatMembersInvited is sent when members are invited to a video chat.
	MessageServiceTypeVideoChatMembersInvited MessageServiceType = "video_chat_members_invited"
	// MessageServiceTypePhoneCallStarted is sent when a phone call is initiated.
	MessageServiceTypePhoneCallStarted MessageServiceType = "phone_call_started"
	// MessageServiceTypePhoneCallEnded is sent when a phone call ends.
	MessageServiceTypePhoneCallEnded MessageServiceType = "phone_call_ended"
	// MessageServiceTypeWebAppData is sent when a Web App sends data to the bot.
	MessageServiceTypeWebAppData MessageServiceType = "web_app_data"
	// MessageServiceTypeUsersShared is sent when users are shared via a keyboard button.
	MessageServiceTypeUsersShared MessageServiceType = "users_shared"
	// MessageServiceTypeChatShared is sent when a chat is shared via a keyboard button.
	MessageServiceTypeChatShared MessageServiceType = "chat_shared"
	// MessageServiceTypeSuccessfulPayment is sent when a payment is successfully completed.
	MessageServiceTypeSuccessfulPayment MessageServiceType = "successful_payment"
	// MessageServiceTypeRefundedPayment is sent when a payment is refunded.
	MessageServiceTypeRefundedPayment MessageServiceType = "refunded_payment"
	// MessageServiceTypeScreenshotTaken is sent when a user takes a screenshot in the chat.
	MessageServiceTypeScreenshotTaken MessageServiceType = "screenshot_taken"
	// MessageServiceTypeGift is sent when a gift is sent in the chat.
	MessageServiceTypeGift MessageServiceType = "gift"
	// MessageServiceTypeSetMessageAutoDeleteTime is sent when auto-delete timer is changed.
	MessageServiceTypeSetMessageAutoDeleteTime MessageServiceType = "set_message_auto_delete_time"
	// MessageServiceTypeChatBoost is sent when a boost is applied to a chat.
	MessageServiceTypeChatBoost MessageServiceType = "chat_boost"
	// MessageServiceTypeConnectedWebsite is sent when the user logs into a website via Telegram.
	MessageServiceTypeConnectedWebsite MessageServiceType = "connected_website"
	// MessageServiceTypeWriteAccessAllowed is sent when write access is granted to a bot via Web App.
	MessageServiceTypeWriteAccessAllowed MessageServiceType = "write_access_allowed"
	// MessageServiceTypeContactRegistered is sent when a contact registers on Telegram.
	MessageServiceTypeContactRegistered MessageServiceType = "contact_registered"
	// MessageServiceTypeProximityAlertTriggered is sent when a proximity alert fires between two users.
	MessageServiceTypeProximityAlertTriggered MessageServiceType = "proximity_alert_triggered"
	// MessageServiceTypeHistoryCleared is sent when chat history is cleared.
	MessageServiceTypeHistoryCleared MessageServiceType = "history_cleared"
	// MessageServiceTypeSuggestProfilePhoto is sent when a profile photo suggestion is made.
	MessageServiceTypeSuggestProfilePhoto MessageServiceType = "suggest_profile_photo"
	// MessageServiceTypeSuggestBirthday is sent when a birthday suggestion is made.
	MessageServiceTypeSuggestBirthday MessageServiceType = "suggest_birthday"
	// MessageServiceTypeChatSetBackground is sent when the chat background wallpaper is changed.
	MessageServiceTypeChatSetBackground MessageServiceType = "chat_set_background"
	// MessageServiceTypeChatSetTheme is sent when the chat theme is changed.
	MessageServiceTypeChatSetTheme MessageServiceType = "chat_set_theme"
	// MessageServiceTypeGiveawayPrizeStars is sent when Stars are awarded as giveaway prizes.
	MessageServiceTypeGiveawayPrizeStars MessageServiceType = "giveaway_prize_stars"
	// MessageServiceTypePaidMessagesRefunded is sent when paid messages are refunded.
	MessageServiceTypePaidMessagesRefunded MessageServiceType = "paid_messages_refunded"
	// MessageServiceTypePaidMessagesPriceChanged is sent when the paid messages price changes.
	MessageServiceTypePaidMessagesPriceChanged MessageServiceType = "paid_messages_price_changed"
	// MessageServiceTypeDirectMessagePriceChanged is sent when the direct message price changes.
	MessageServiceTypeDirectMessagePriceChanged MessageServiceType = "direct_message_price_changed"
	// MessageServiceTypeChecklistTasksDone is sent when checklist tasks are marked complete.
	MessageServiceTypeChecklistTasksDone MessageServiceType = "checklist_tasks_done"
	// MessageServiceTypeChecklistTasksAdded is sent when tasks are added to a checklist.
	MessageServiceTypeChecklistTasksAdded MessageServiceType = "checklist_tasks_added"
	// MessageServiceTypeUpgradedGiftPurchaseOffer is sent when an upgraded gift purchase is offered.
	MessageServiceTypeUpgradedGiftPurchaseOffer MessageServiceType = "upgraded_gift_purchase_offer"
	// MessageServiceTypeUpgradedGiftPurchaseOfferRejected is sent when an upgraded gift offer is rejected.
	MessageServiceTypeUpgradedGiftPurchaseOfferRejected MessageServiceType = "upgraded_gift_purchase_offer_rejected"
	// MessageServiceTypeChatHasProtectedContentToggled is sent when content protection is toggled.
	MessageServiceTypeChatHasProtectedContentToggled MessageServiceType = "chat_has_protected_content_toggled"
	// MessageServiceTypeChatHasProtectedContentDisableRequested is sent when disabling protection is requested.
	MessageServiceTypeChatHasProtectedContentDisableRequested MessageServiceType = "chat_has_protected_content_disable_requested"
	// MessageServiceTypeSuggestedPostApprovalFailed is sent when a suggested post fails approval.
	MessageServiceTypeSuggestedPostApprovalFailed MessageServiceType = "suggested_post_approval_failed"
	// MessageServiceTypeSuggestedPostApproved is sent when a suggested post is approved.
	MessageServiceTypeSuggestedPostApproved MessageServiceType = "suggested_post_approved"
	// MessageServiceTypeSuggestedPostDeclined is sent when a suggested post is declined.
	MessageServiceTypeSuggestedPostDeclined MessageServiceType = "suggested_post_declined"
	// MessageServiceTypeSuggestedPostPaid is sent when payment for a suggested post is made.
	MessageServiceTypeSuggestedPostPaid MessageServiceType = "suggested_post_paid"
	// MessageServiceTypeSuggestedPostRefunded is sent when a suggested post payment is refunded.
	MessageServiceTypeSuggestedPostRefunded MessageServiceType = "suggested_post_refunded"
)

// String returns the string representation of the MessageServiceType.
func (m MessageServiceType) String() string { return string(m) }
